const CATS = {
  projekte:{num:'01',name:'Projects & Science',desc:'University projects, scientific papers and interdisciplinary experiments — everything that emerges during studies and beyond.',icon:'<svg width="44" height="44" viewBox="0 0 44 44" fill="none" style="color:var(--tan)"><path d="M22 42C22 42 4 30 4 17C4 8 12.3 2 22 2C31.7 2 40 8 40 17C40 30 22 42 22 42Z" stroke="currentColor" stroke-width="1.4" fill="none"/><line x1="22" y1="42" x2="22" y2="8" stroke="currentColor" stroke-width="1"/><line x1="22" y1="28" x2="33" y2="17" stroke="currentColor" stroke-width=".8" opacity=".55"/><line x1="22" y1="22" x2="11" y2="11" stroke="currentColor" stroke-width=".8" opacity=".35"/></svg>'},
  organisation:{num:'02',name:'Organisation & Tools',desc:'Self-developed methods, systems and digital tools for structured, efficient working — in studies and everyday life.',icon:'<svg width="44" height="44" viewBox="0 0 44 44" fill="none" style="color:var(--tan)"><rect x="4" y="4" width="16" height="16" stroke="currentColor" stroke-width="1.4" fill="none"/><rect x="24" y="4" width="16" height="16" stroke="currentColor" stroke-width="1.4" fill="none"/><rect x="4" y="24" width="16" height="16" stroke="currentColor" stroke-width="1.4" fill="none"/><rect x="24" y="24" width="16" height="16" stroke="currentColor" stroke-width="1.4" fill="none"/></svg>'},
  ki:{num:'03',name:'AI & Creativity',desc:'Experiments with AI tools, creative digital processes and self-taught skills in working with artificial intelligence.',icon:'<svg width="44" height="44" viewBox="0 0 44 44" fill="none" style="color:var(--tan)"><circle cx="22" cy="22" r="10" stroke="currentColor" stroke-width="1.4" fill="none"/><line x1="22" y1="6" x2="22" y2="12" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/><line x1="22" y1="32" x2="22" y2="38" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/><line x1="6" y1="22" x2="12" y2="22" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/><line x1="32" y1="22" x2="38" y2="22" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/><circle cx="22" cy="22" r="3" fill="currentColor"/></svg>'}
};

const POSTS=[
  {id:1,cat:'ki',title:'Prompt Engineering — How to Actually Talk to AI',date:'April 18, 2026',excerpt:'Most people treat AI like a search engine. But the way you phrase your prompt is everything — and once you understand that, the whole thing changes.',tags:['AI','Prompt Engineering','ChatGPT'],read:'8 min',url:'entries/prompt-engineering.html'},
];

let currentPage='home',currentCat=null;

function goHome(){currentPage='home';currentCat=null;document.documentElement.scrollTop=0;render()}
function goCat(id){currentPage='cat';currentCat=id;document.documentElement.scrollTop=0;render()}
function goSection(id){setTimeout(()=>{const el=document.getElementById(id);if(el)el.scrollIntoView({behavior:'smooth'})},200)}
function navTo(id){
  if(currentPage!=='home'){currentPage='home';currentCat=null;render();setTimeout(()=>{const el=document.getElementById(id);if(el)el.scrollIntoView({behavior:'smooth'})},250)}
  else{const el=document.getElementById(id);if(el)el.scrollIntoView({behavior:'smooth'})}
}

function render(){
  document.getElementById('app').innerHTML=currentPage==='home'?homeHTML():catHTML(currentCat);
  initReveal();
}

function homeHTML(){
  const latest=[...POSTS].sort((a,b)=>b.id-a.id).slice(0,3);
  return`
<section class="hero">
  <div class="hero-left">
    <p class="eyebrow reveal" style="margin-bottom:2rem">Knowledge Documentation · Open Source · Portfolio</p>
    <h1 class="hero-title reveal d1">Open<br><em>Leaf</em><br>Library</h1>
    <p class="hero-sub reveal d1">A personal knowledge library</p>
    <p class="hero-desc reveal d2">University projects, self-taught skills and collected insights — openly documented and shared. That's Open Leaf Library.</p>

  </div>
  <div class="hero-right">
    <svg class="hero-leaf-bg" viewBox="0 0 400 480" fill="none">
      <path d="M200 470C200 470 20 360 20 200C20 90 100 10 200 10C300 10 380 90 380 200C380 360 200 470 200 470Z" fill="#D6AC88"/>
      <line x1="200" y1="470" x2="200" y2="60" stroke="#FBF5EC" stroke-width="2.5"/>
      <line x1="200" y1="340" x2="310" y2="230" stroke="#FBF5EC" stroke-width="1.5" opacity=".4"/>
      <line x1="200" y1="290" x2="90" y2="180" stroke="#FBF5EC" stroke-width="1.5" opacity=".25"/>
    </svg>
  </div>
</section>

<section id="about" class="about-section">
  <div class="reveal d1" style="align-self:start">
    <p class="section-label">About Me</p>
    <h2 class="section-title">Hi, I'm<br><em>Sylvi Garzarella</em></h2>
    <p class="section-body">I study Industrial Engineering for Life Sciences at Hochschule Fulda. Open Leaf Library is my personal knowledge space — here I document what I learn during my studies, what I teach myself and what drives me forward.</p>
    <p class="section-body">I'm fascinated by the intersection of creativity, technology and knowledge. The discovering, the experimenting, the capturing of insights — this library is my living notebook, constantly growing.</p>
    <p class="section-body">Alongside my studies, I explore AI tools, design projects and the question of how knowledge can be documented in a way that stays truly accessible and useful — for me and for others.</p>
    <div class="about-stats">
      <div class="stat-box"><span class="stat-num">${POSTS.length}</span><span class="stat-lbl">Entries</span></div>
      <div class="stat-box"><span class="stat-num">100%</span><span class="stat-lbl">Open Source</span></div>
    </div>
  </div>
  <div class="photo-wrap reveal">
    <img src="data:image/jpeg;base64," alt="Sylvi Garzarella" style="position:absolute;inset:0;width:100%;height:100%;object-fit:contain;object-position:top center;display:block">
    </div>
  </div>
</section>

<div class="divider"></div>

<section id="categories" style="background:var(--cocoa);padding:7rem 5rem">
  <div class="cat-header">
    <div class="reveal">
      <p class="section-label" style="color:var(--cape)">Knowledge Areas</p>
      <h2 class="section-title" style="color:var(--cream);font-size:2.4rem;margin-bottom:0">What awaits you</h2>
    </div>
    <p class="reveal d1" style="font-size:.78rem;color:rgba(214,172,136,.3);max-width:200px;line-height:1.8;font-weight:300;text-align:right">Click an area to see all entries.</p>
  </div>
  <div class="cat-grid">
    ${Object.entries(CATS).map(([id,c],i)=>`
    <button class="cat-card reveal ${i?'d'+i:''}" onclick="goCat('${id}')">
      <span class="cat-num">${c.num}</span>
      <div style="margin-bottom:1.8rem">${c.icon}</div>
      <span class="cat-name">${c.name}</span>
      <span class="cat-desc">${c.desc}</span>
      <span class="cat-count">${POSTS.filter(p=>p.cat===id).length} entries</span>
      <svg class="cat-arrow" width="24" height="24" viewBox="0 0 26 26" fill="none">
        <path d="M5 13H21M15 7L21 13L15 19" stroke="currentColor" stroke-width="1.2" stroke-linecap="round"/>
      </svg>
    </button>`).join('')}
  </div>
</section>

<div class="divider"></div>

<section id="latest" style="background:var(--cream);padding:8rem 5rem">
  <div style="display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:3.5rem">
    <div class="reveal">
      <p class="section-label">Knowledge Library</p>
      <h2 class="section-title" style="margin-bottom:0">Latest <em>Entries</em></h2>
    </div>
  </div>
  <div class="posts-grid">
    ${latest.map((p,i)=>postCardHTML(p,i)).join('')}
  </div>
</section>`;
}

function catHTML(id){
  const c=CATS[id];
  const filtered=POSTS.filter(p=>p.cat===id).sort((a,b)=>b.id-a.id);
  return`
<section class="cat-hero">
  <button class="back-btn reveal" onclick="goHome()">
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M10 3L5 8L10 13" stroke="currentColor" stroke-width="1.2" stroke-linecap="round"/></svg>
    Zurück zur Übersicht
  </button>
  <div class="cat-hero-inner">
    <p class="section-label reveal d1" style="color:var(--cape)">${c.num} / Knowledge Area</p>
    <h1 class="section-title reveal d2" style="color:var(--cream);font-size:clamp(2.5rem,4.5vw,4.5rem);margin-bottom:1rem">${c.name}</h1>
    <p class="reveal d3" style="font-size:.92rem;color:rgba(214,172,136,.42);line-height:1.9;max-width:540px;font-weight:300">${c.desc}</p>
    <p class="reveal d3" style="margin-top:1.5rem;font-size:.62rem;letter-spacing:.18em;text-transform:uppercase;color:rgba(154,100,73,.45)">${filtered.length} entries</p>
  </div>
</section>
<section style="background:var(--cream);padding:5rem">
  <div class="posts-list">
    ${filtered.length
      ?filtered.map((p,i)=>postRowHTML(p,i)).join('')
      :`<div class="empty-state"><p>No entries in this area yet.</p></div>`}
  </div>
</section>`;
}

function postCardHTML(p,i){
  const c=CATS[p.cat];
  return`<a class="post-card reveal ${i?'d'+i:''}" href="${p.url||'#'}" style="text-decoration:none">
  <p class="post-cat-label">${c.name}</p>
  <p class="post-date">${p.date}</p>
  <h3 class="post-title">${p.title}</h3>
  <p class="post-excerpt">${p.excerpt}</p>
  <div class="post-meta">
    <div class="post-tags">${p.tags.map(t=>`<span class="ptag">${t}</span>`).join('')}</div>
    <span class="post-read">${p.read}</span>
  </div>
</a>`;
}

function postRowHTML(p,i){
  return`<a class="post-row reveal ${i?'d1':''}" href="${p.url||'#'}" style="text-decoration:none">
  <div class="post-row-date">${p.date}<br><span style="font-size:.62rem;color:rgba(50,37,37,.22)">${p.read} read</span></div>
  <div>
    <h3 class="post-row-title">${p.title}</h3>
    <p class="post-row-excerpt">${p.excerpt}</p>
    <div class="post-row-tags">${p.tags.map(t=>`<span class="ptag">${t}</span>`).join('')}</div>
  </div>
  <div style="padding-top:.2rem;color:var(--cape)">
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none"><path d="M4 10H16M12 6L16 10L12 14" stroke="currentColor" stroke-width="1.1" stroke-linecap="round"/></svg>
  </div>
</a>`;
}

function initReveal(){
  const obs=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting)e.target.classList.add('in')})},{threshold:.1});
  document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));
  setTimeout(()=>{document.querySelectorAll('.hero .reveal,.cat-hero .reveal').forEach(el=>el.classList.add('in'))},80);
}

render();